function countVowelsAndConsonants(str) {
  let vowelsCount = 0;
  let consonantsCount = 0;

  // Define vowels for easy lookup
  const vowels = "aeiouAEIOU";

  for (let char of str) {
    // Check if the character is a letter using a Regular Expression
    if (/[a-zA-Z]/.test(char)) {
      if (vowels.includes(char)) {
        vowelsCount++;
      } else {
        consonantsCount++;
      }
    }
  }

  console.log(`vowels count: ${vowelsCount}`);
  console.log(`consonants: ${consonantsCount}`);
}

// Example usage
countVowelsAndConsonants("HelloWorld"); 
// Output: vowels count: 3, consonants: 7
